 1	//! 配置管理模块
 2	//!
 3	//! API Key 存储、应用配置读写、数据目录管理
 4	
 5	use serde::{Deserialize, Serialize};
 6	use std::fs;
 7	use std::path::PathBuf;
 8	use tauri::State;
 9	use crate::crypto::{encrypt_api_key, decrypt_api_key};
10	
11	/// 数据目录名（~/.aiagent/）
12	const DATA_DIR: &str = ".aiagent";
13	
14	/// 应用配置
15	#[derive(Debug, Clone, Serialize, Deserialize)]
16	pub struct AppConfig {
17	    pub theme: String,
18	    pub locale: String,
19	    pub default_workspace_path: String,
20	    pub sidecar_port_start: u16,
21	    pub auto_start: bool,
22	}
23	
24	impl Default for AppConfig {
25	    fn default() -> Self {
26	        Self {
27	            theme: "system".to_string(),
28	            locale: "zh-CN".to_string(),
29	            default_workspace_path: "~".to_string(),
30	            sidecar_port_start: 31415,
31	            auto_start: false,
32	        }
33	    }
34	}
