36	/// 供应商配置
37	#[derive(Debug, Clone, Serialize, Deserialize)]
38	pub struct ProviderConfig {
39	    pub id: String,
40	    pub name: String,
41	    pub base_url: String,
42	    pub api_key: String,
43	    pub is_default: bool,
44	    pub enabled: bool,
45	    #[serde(default)]
46	    pub endpoint_type: String,
47	    #[serde(default)]
48	    pub is_custom: bool,
49	}
50	
51	/// 配置管理器
52	pub struct ConfigManager {
53	    data_dir: PathBuf,
54	}
55	
56	impl ConfigManager {
57	    /// 创建配置管理器，自动创建数据目录
58	    pub fn new() -> Self {
59	        let home = dirs::home_dir().unwrap_or_else(|| PathBuf::from("."));
60	        let data_dir = home.join(DATA_DIR);
61	
62	        // 确保目录存在
63	        let _ = fs::create_dir_all(&data_dir);
64	        let _ = fs::create_dir_all(data_dir.join("sessions"));
65	        let _ = fs::create_dir_all(data_dir.join("skills"));
66	        let _ = fs::create_dir_all(data_dir.join("memory"));
67	        let _ = fs::create_dir_all(data_dir.join("logs"));
68	
69	        Self { data_dir }
70	    }
71	
72	    /// 获取数据目录路径
73	    pub fn data_dir(&self) -> &PathBuf {
74	        &self.data_dir
75	    }
76	
77	    /// 读取应用配置
78	    pub fn read_app_config(&self) -> AppConfig {
79	        let config_path = self.data_dir.join("config.json");
80	        if let Ok(content) = fs::read_to_string(&config_path) {

 80	        if let Ok(content) = fs::read_to_string(&config_path) {
 81	            serde_json::from_str(&content).unwrap_or_default()
 82	        } else {
 83	            AppConfig::default()
 84	        }
 85	    }
 86	
 87	    /// 保存应用配置
 88	    pub fn save_app_config(&self, config: &AppConfig) -> Result<(), String> {
 89	        let config_path = self.data_dir.join("config.json");
 90	        let json = serde_json::to_string_pretty(config).map_err(|e| e.to_string())?;
 91	        fs::write(&config_path, json).map_err(|e| format!("保存配置失败: {}", e))
 92	    }
 93	
 94	    /// 读取供应商配置列表（自动解密 API Key）
 95	    pub fn read_providers(&self) -> Vec<ProviderConfig> {
 96	        let path = self.data_dir.join("providers.json");
 97	        if let Ok(content) = fs::read_to_string(&path) {
 98	            let mut providers: Vec<ProviderConfig> = serde_json::from_str(&content).unwrap_or_default();
 99	            // 自动解密 API Key
100	            for provider in &mut providers {
101	                if !provider.api_key.is_empty() {
102	                    if let Ok(decrypted) = decrypt_api_key(&provider.api_key) {
103	                        provider.api_key = decrypted;
104	                    }
105	                }
106	            }
107	            providers
108	        } else {
109	            Vec::new()
110	        }
111	    }
112	
113	    /// 保存供应商配置列表（自动加密 API Key）
114	    pub fn save_providers(&self, providers: &[ProviderConfig]) -> Result<(), String> {
115	        let path = self.data_dir.join("providers.json");
116	        let mut encrypted_providers = providers.to_vec();
117	        // 自动加密 API Key
118	        for provider in &mut encrypted_providers {
119	            if !provider.api_key.is_empty() {
120	                provider.api_key = encrypt_api_key(&provider.api_key)?;
121	            }
122	        }
123	        let json = serde_json::to_string_pretty(&encrypted_providers).map_err(|e| e.to_string())?;
124	        fs::write(&path, json).map_err(|e| format!("保存供应商配置失败: {}", e))
125	    }
126	
127	    /// 迁移现有的明文 API Key 为加密格式
128	    pub fn migrate_providers_encryption(&self) -> Result<(), String> {
129	        let providers = self.read_providers();
130	        if !providers.is_empty() {
131	            self.save_providers(&providers)?;
132	        }
133	        Ok(())
134	    }
135	}
